hrm{u}\\mathrm{l}\\mathrm{t}\\mathrm{s}\\;\\mathrm{a}\\mathrm{r}\\mathrm{e}\\;\\mathrm{v}\\mathrm{e}\\mathrm{r}\\mathrm{y}\\;\\mathrm{c}\\mathrm{l}\\mathrm{o}\\mathrm{s}\\mathrm{e}\\;\\mathrm{t}\\mathrm{o}\\;\\mathrm{t}\\mathrm{h}\\mathrm{e}\\;\\mathrm{s}\\mathrm{i}\\mathrm{m}\\mathrm{u}\\mathrm{l}\\mathrm{a}\\mathrm{t}\\mathrm{i}\\mathrm{o}\\mathrm{n}\\;\\mathrm{r}\\mathrm{e}\\mathrm{u}\\mathrm{l}\\mathrm{t}\\mathrm{s}:\\mathrm{o}\\mathrm{f}\\mathrm{f}\\;\\mathrm{b}\\mathrm{y}\\;\n\\end{array}${"editStyle":"visual"} 
